/**
 * Custom Jest Resolver — SWC @/ Alias Fix
 *
 * Problem: SWC resolves @/ aliases before Jest's moduleNameMapper runs,
 * which causes module-not-found errors in test environments.
 *
 * Solution: This resolver intercepts @/ prefixed imports and manually
 * resolves them to the src/ directory before falling through to the
 * default resolver.
 *
 * Usage: Add `resolver: '<rootDir>/jest-resolver.cjs'` to your jest config.
 *
 * Generated by New-Project-Starter-Kit
 */

const path = require('path');

module.exports = (request, options) => {
  // If request starts with @/ alias, resolve it to the src directory
  if (request.startsWith('@/')) {
    const resolvedPath = path.resolve(
      options.rootDir || process.cwd(),
      'src',
      request.slice(2),
    );

    // Try common extensions
    const extensions = ['.ts', '.tsx', '.js', '.jsx', '.json'];
    for (const ext of extensions) {
      try {
        return options.defaultResolver(resolvedPath + ext, options);
      } catch (e) {
        // Try next extension
      }
    }

    // Try as directory with index file
    for (const ext of extensions) {
      try {
        return options.defaultResolver(
          path.join(resolvedPath, 'index' + ext),
          options,
        );
      } catch (e) {
        // Try next
      }
    }
  }

  // Fall through to default resolver
  return options.defaultResolver(request, options);
};
